import React, { useEffect, useState, useRef } from "react";



import { getStore, updStore, gen16CodeId, compareJSON, qryStore, fetchEncryptStream } from "../../../stores/Utils";

import { CheckBoxSlide_Cmpt, TextInput_Cmpt, CheckBox_Cmpt, DropDwnPicker_Cmpt } from "../../../components";
import { OpenModal, CloseModal } from "../../../components/DialogHRM";


import DateCalComponent from "./DateCalComponent";



const TextInput = TextInput_Cmpt();



const CheckBoxSlide = CheckBoxSlide_Cmpt();


const DropDwnPicker = DropDwnPicker_Cmpt();


const frmNm = "add_client"

const AddClientInfo  = ({ data, elmId, confirm }) => {
	const [initialize, setInitialize] = useState(false);
	const [obs, set_obs] = useState(0);

	useEffect(() => {
		if (!initialize) {
			setInitialize(true);
			
			set_obs(gen16CodeId())
		}
	});

	const updFrm = (f, v, k) => {
		let frm2 = getStore(frmNm) || {};
		if(k){
			if( !frm2[k]){
				frm2[k] = {};
			}
			frm2[k][f] = v;
		}else{
			frm2[f] = v;
		}
		updStore(frmNm, frm2);
		
		set_obs(gen16CodeId())
	};


	const print  = async ()  => {
		let ffm = getStore(frmNm);

		if(ffm && ffm["dateOfBirth"]){
			let nd = (new Date(ffm["dateOfBirth"])).getTime();
			if(nd){
				ffm["dob"] = nd;
			}
		}
		ffm["clientNotaryId"] = gen16CodeId();


		
		let bdyq2 = {...getStore(qryStore())?.add_notary};
		bdyq2.form = ffm;	
		
		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && !td.error) {
			updStore(frmNm, null);
			set_obs(gen16CodeId())
			close();
			confirm && confirm();
		}
		///let pdfUri = await generateTranslateAddClient(ffm, true, true);
		///window.open(pdfUri);
	};


	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}

	
	const handlePick = (v,f)=>{
		updFrm(f,v.clientNotaryId)
	}

	

	return (
		<div style={{
			maxHeight: "80vh",
			width: "960px",
			overflow: "auto",
			background: "var(--dark-800)",
			borderRadius: 13,
			padding: "10px 19px"
		}}>
			<div className="_dsplFlx ">
				<p className="form_title ">
					Agregar Cliente
				</p>
				<div className="flexSpace"/>
				
			</div>

			<div className="_dsplFlx " style={{marginTop: 10}}>
				<div className="flexSpace"/>
				<div style={{margin:"30px 10px 0 0"}}>
					<DateCalComponent  
						init={getStore(frmNm)?.["dateOfBirth"]} 
						label={"Fecha de nacimiento"}
						updDate={(e)=>updFrm("dateOfBirth",e)}
					/>
				</div>
				<div className="flexSpace"/>
				
				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["genre"]}
						lbl_empty={"Sexo"} 
						list={[
							{label: "Mujer", id:"Female"},
							{label: "Hombre", id:"Male"}
							
						]} 
						onSelect={(e)=>updFrm("genre",e.id)}
						background={"var(--dark-900)"}
						color={"var(--primary)"}
					/>
				</div>	
				<div className="flexSpace"/>
			

				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["maritalStatus"]}
						lbl_empty={"Estado Civil"} 
						list={[
							{label: "Soltero", id:"Single"},
							{label: "Casado", id:"Married"},
							{label: "Divorciado", id:"Divorced"},
							{label: "Viudo", id:"Widowed"}
						]} 
						onSelect={(e)=>updFrm("maritalStatus",e.id)}
						direction={"right"} 
						background={"var(--dark-900)"}
						color={"var(--primary)"}
					/>
				</div>	
				<div className="flexSpace"/>
				<div style={{marginTop:39}}>
					<DropDwnPicker 
						init={getStore(frmNm)?.["race"]}
						lbl_empty={"raza"} 
						list={
							[
								{label: "Hispanic or Latino", id:"Hispanic or Latino"},
								{label: "American White", id:"American White"},
								{label: "African", id:"African"},
							]
						}
						onSelect={(e)=>updFrm("race",e.id)} 
						background={"var(--dark-900)"}
						color={"var(--primary)"}
					/>
				</div>	
				<div className="flexSpace"/>
				
				
			</div>

			
			<div className="_dsplFlx spaceAround flxWrp " style={{marginTop: 10}}>
			
				
				<TextInput  
					init={getStore(frmNm)?.["firstName"]} 
					label={"Nombre"} 
					width={200} 
					updChanges={(e)=>updFrm("firstName",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["middleName"]} 
					label={"Segundo Nombre"} 
					width={200} 
					updChanges={(e)=>updFrm("middleName",e)}
				/>
				<TextInput  
					init={getStore(frmNm)?.["lastName"]} 
					label={"Apellidos"} 
					width={360} 
					updChanges={(e)=>updFrm("lastName",e)}
				/>
				
			</div>


		
			<div className="_dsplFlx spaceAround flxWrp " style={{marginTop: 10}}>
				
				<TextInput  
					init={getStore(frmNm)?.["phoneNumber"]} 
					label={"Telefono"} 
					width={160} 
					updChanges={(e)=>updFrm("phoneNumber",e)}
				/>
				
			</div>




			
			<div className="separator"/>


			

			<p className="group_title">
				Lugar de Nacimiento 
			</p>
			<div className="_dsplFlx spaceAround flxWrp"> 
				
				<TextInput 
					init={getStore(frmNm)?.["placeOfBirth"]?.["city"]} 
					label={"Municipio"} 
					width={200} 
					updChanges={(e)=>updFrm("city",e, "placeOfBirth")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["placeOfBirth"]?.["state"]} 
					label={"Provincia"} 
					width={200} 
					updChanges={(e)=>updFrm("state",e, "placeOfBirth")}
				/>
				<TextInput  
					init={getStore(frmNm)?.["placeOfBirth"]?.["country"]} 
					label={"Pais"} 
					width={200} 
					updChanges={(e)=>updFrm("country",e, "placeOfBirth")}
				/>
				
			</div>
			<div className="_dsplFlx spaceAround flxWrp" style={{marginTop: 20}}> 
				<TextInput  
					init={getStore(frmNm)?.["countryOfCitizenship"]} 
					label={"Ciudadania"} 
					width={200} 
					updChanges={(e)=>updFrm("countryOfCitizenship",e)}
				/>
				<div className="_dsplFlx " style={{marginTop: 40}}>
					<CheckBoxSlide
						initvalue={getStore(frmNm)?.["isInUSA"]}
						keyCode={57}
						updChange={(e)=>updFrm("isInUSA",e)}
						color={"var(--primary)"}
					/>
					<span className={`checklabel`}>
						{"esta en USA"}
					</span>
				</div>
				<TextInput  
					init={getStore(frmNm)?.["currentLocation"]?.["state"]} 
					label={"Estado de Recidencia Actual"} 
					width={200} 
					updChanges={(e)=>updFrm("state",e, "currentLocation")}
				/>

				<TextInput  
					init={getStore(frmNm)?.["currentLocation"]?.["country"]} 
					label={"Pais de Recidencia Actual"} 
					width={200} 
					updChanges={(e)=>updFrm("country",e, "currentLocation")}
				/>

				
			</div>

		


			<div className="_dsplFlx ">
				<div className="flexSpace"/>
				<div className="card">
					<GrayButton label={"Agregar"} clickHandler={print}/>
				</div>
			</div>
		</div>
	);
};

export default AddClientInfo;




const GrayButton  = ({ clickHandler, label }) => {
	return (
		<div className=" jaqJnq_hrm1"  >
			<button className="gHAsFI_hrm1 dqnOfN jUrKkb" onClick={clickHandler}>
				<span className=" jaqJnq_hrm1" >
					{label}
				</span>
			</button>
		</div>
	)
}